#[test]
fn binary_dispatches_chmod_grants_public_read() {
    // Grant read to the built-in `public` group on a fresh data object;
    // re-list with --acl and assert the entry is present. Exercises
    // chmod through the binary plus a follow-up list to verify the
    // grant landed.
    let local = "/tmp/baton_rs_bin_chmod_src";
    std::fs::write(local, b"binary chmod").expect("write");
    let name = unique_name("baton_rs_bin_chmod");
    let remote = format!("{}/{}", TEST_COLL, name);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote);

    let do_target = DataObject {
        collection: TEST_COLL.to_string(),
        data_object: name.clone(),
        size: None,
        checksum: None,
        data: None,
        directory: None,
        file: None,
        avus: None,
        access: Some(vec![Acl {
            owner: "public".to_string(),
            level: baton_rs::AclLevel::Read,
            zone: None,
        }]),
        replicates: None,
        timestamps: None,
        error: None,
    };
    let env = BatonDoEnvelope::new_standard(
        Operation::Chmod,
        Target::DataObject(do_target),
        Arguments::default(),
    );

    // Then list with --acl on the same object to see the grant.
    let mut list_args = Arguments::default();
    list_args.acl = true;
    let list_env = BatonDoEnvelope::new_standard(
        Operation::List,
        data_object_target(TEST_COLL, &name),
        list_args,
    );

    let input = format!(
        "{}{}",
        one_envelope_line(env),
        one_envelope_line(list_env),
    );
    let output = run_baton_do(&[], &input);
    assert_success_exit(&output);

    let outputs = parse_outputs(&stdout_str(&output));
    assert_eq!(outputs.len(), 2, "two output lines (chmod + list)");
    assert!(outputs[0].error.is_none(), "chmod error: {:?}", outputs[0].error);

    match outputs[1].result.as_ref().expect("list result") {
        OperationResult::Single(Target::DataObject(d)) => {
            let access = d.access.as_ref().expect("access populated");
            assert!(
                access.iter().any(|a| a.owner == "public"
                    && matches!(a.level, baton_rs::AclLevel::Read)),
                "expected public:read in access list, got {:?}",
                access,
            );
        }
        other => panic!("expected Single(DataObject), got {:?}", other),
    }
}

