#[test]
fn binary_dispatches_checksum_rejects_verify_and_calculate_combo() {
    // arguments.checksum + arguments.verify both true is the
    // upstream USER_INPUT_OPTION_ERR case (`baton/src/read.c:603-607`).
    // baton-rs surfaces it as an in-band annotated error from
    // checksum_one (mirroring the message), with the wire shape
    // keeping the stream alive — same pattern as other annotated
    // failures.
    let local = "/tmp/baton_rs_bin_cksum_combo_src";
    std::fs::write(local, b"binary cksum combo").expect("write");
    let name = unique_name("baton_rs_bin_cksum_combo");
    let remote = format!("{}/{}", TEST_COLL, name);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote);

    let mut args = Arguments::default();
    args.checksum = true;
    args.verify = true;
    let env = BatonDoEnvelope::new_standard(
        Operation::Checksum,
        data_object_target(TEST_COLL, &name),
        args,
    );
    // --no-error so the in-band annotation is observable without
    // the binary's per-input-error exit-code policy interfering.
    // The exit-code policy itself is covered by
    // `no_error_flag_suppresses_nonzero_exit_on_per_input_error`.
    let output = run_baton_do(&["--no-error"], &one_envelope_line(env));
    assert_success_exit(&output);

    let outputs = parse_outputs(&stdout_str(&output));
    assert_eq!(outputs.len(), 1);
    let err = outputs[0]
        .error
        .as_ref()
        .expect("verify+calculate must be rejected");
    assert!(
        err.message.to_lowercase().contains("verify")
            && err.message.to_lowercase().contains("calculate"),
        "error message should mention both flags: {:?}",
        err.message
    );
}

