#[test]
fn no_error_flag_suppresses_nonzero_exit_on_per_input_error() {
    // Reference a non-existent data object to provoke an in-band
    // error; with --no-error the exit code stays 0, without it the
    // dispatcher's per-input failure should bubble up to exit 1.
    let missing = unique_name("baton_rs_bin_missing");
    let env = BatonDoEnvelope::new_standard(
        Operation::List,
        data_object_target(TEST_COLL, &missing),
        Arguments::default(),
    );
    let input = one_envelope_line(env);

    let without = run_baton_do(&[], &input);
    assert!(
        !without.status.success(),
        "in-band error should produce non-zero exit: stdout={}",
        stdout_str(&without),
    );

    let with = run_baton_do(&["--no-error"], &input);
    assert!(
        with.status.success(),
        "--no-error should force exit 0: status={:?}",
        with.status,
    );

    // Either way the in-band annotation is on the output line.
    let outputs = parse_outputs(&stdout_str(&with));
    assert_eq!(outputs.len(), 1);
    assert!(
        outputs[0].error.is_some(),
        "in-band error annotation should still be present with --no-error",
    );
}

#[test]
fn parse_failure_is_annotated_and_stream_continues() {
    // Two input lines: one unparseable, one a valid list envelope.
    // The malformed line emits a stand-alone {"error": ...} and the
    // good line still gets dispatched. Exit status is non-zero
    // because we had at least one error.
    let local = "/tmp/baton_rs_bin_parsefail_src";
    std::fs::write(local, b"binary parsefail").expect("write");
    let name = unique_name("baton_rs_bin_parsefail");
    let remote = format!("{}/{}", TEST_COLL, name);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote);

    let good = one_envelope_line(BatonDoEnvelope::new_standard(
        Operation::List,
        data_object_target(TEST_COLL, &name),
        Arguments::default(),
    ));
    let input = format!("not-json\n{}", good);

    let output = run_baton_do(&[], &input);
    assert!(
        !output.status.success(),
        "parse failure should produce non-zero exit",
    );

    let lines = parse_value_lines(&stdout_str(&output));
    assert_eq!(lines.len(), 2, "one parse-error line + one list line");
    assert!(
        lines[0].get("error").is_some(),
        "first line should be a stand-alone error: {}",
        lines[0],
    );
    // Second line is a fully-formed envelope.
    assert!(
        lines[1].get("operation").is_some(),
        "second line should be a normal output envelope: {}",
        lines[1],
    );
}

#[test]
fn unknown_operation_discriminator_is_annotated_and_stream_continues() {
    // Lexically valid JSON with an unknown `operation` value
    // exercises a different deserialise path from `not-json`:
    // the envelope visitor rejects when parsing the Operation
    // enum, not at JSON-syntax level. Should still surface as a
    // stand-alone {"error": ...} line and the stream should
    // continue — same observable behaviour as a syntactic parse
    // failure.
    let local = "/tmp/baton_rs_bin_unknownop_src";
    std::fs::write(local, b"binary unknownop").expect("write");
    let name = unique_name("baton_rs_bin_unknownop");
    let remote = format!("{}/{}", TEST_COLL, name);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote);

    let bad = r#"{"operation":"frobnicate","target":{"collection":"/x"}}"#;
    let good = one_envelope_line(BatonDoEnvelope::new_standard(
        Operation::List,
        data_object_target(TEST_COLL, &name),
        Arguments::default(),
    ));
    let input = format!("{}\n{}", bad, good);

    let output = run_baton_do(&[], &input);
    assert!(
        !output.status.success(),
        "unknown operation discriminator should produce non-zero exit",
    );

    let lines = parse_value_lines(&stdout_str(&output));
    assert_eq!(
        lines.len(),
        2,
        "one error line + one list line: {:?}",
        lines
    );
    assert!(
        lines[0].get("error").is_some(),
        "first line should be a stand-alone error: {}",
        lines[0],
    );
    assert!(
        lines[1].get("operation").is_some(),
        "second line should be a normal output envelope: {}",
        lines[1],
    );
}

#[test]
fn file_arg_reads_envelopes_from_disk() {
    // Same test as the list smoke, but inputs come from --file
    // instead of stdin.
    let local = "/tmp/baton_rs_bin_filearg_src";
    std::fs::write(local, b"binary filearg").expect("write");
    let name = unique_name("baton_rs_bin_filearg");
    let remote = format!("{}/{}", TEST_COLL, name);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote);

    let env = BatonDoEnvelope::new_standard(
        Operation::List,
        data_object_target(TEST_COLL, &name),
        Arguments::default(),
    );
    let input_file = format!("/tmp/baton_rs_bin_filearg_input_{}", std::process::id());
    std::fs::write(&input_file, one_envelope_line(env)).expect("write input file");

    // Empty stdin: --file is the input source.
    let output = run_baton_do(&["--file", &input_file], "");
    let _ = std::fs::remove_file(&input_file);
    assert_success_exit(&output);

    let outputs = parse_outputs(&stdout_str(&output));
    assert_eq!(outputs.len(), 1);
    assert!(outputs[0].error.is_none(), "list error: {:?}", outputs[0].error);
}

#[test]
fn multiple_records_dispatched_in_one_invocation() {
    // Three records of three different operation kinds (mkdir, list,
    // rmdir) in one stream — exercises the loop and the per-record
    // dispatch routing in sequence.
    let name = unique_name("baton_rs_bin_multi");
    let coll = format!("{}/{}", TEST_COLL, name);
    let _cleanup = IrodsCleanup(coll.clone());

    let mkdir_env = BatonDoEnvelope::new_standard(
        Operation::Mkdir,
        collection_target(&coll),
        Arguments::default(),
    );
    let list_env = BatonDoEnvelope::new_standard(
        Operation::List,
        collection_target(&coll),
        Arguments::default(),
    );
    let mut rmdir_args = Arguments::default();
    rmdir_args.force = true;
    let rmdir_env = BatonDoEnvelope::new_standard(
        Operation::Rmdir,
        collection_target(&coll),
        rmdir_args,
    );

    let input = format!(
        "{}{}{}",
        one_envelope_line(mkdir_env),
        one_envelope_line(list_env),
        one_envelope_line(rmdir_env),
    );
    let output = run_baton_do(&[], &input);
    assert_success_exit(&output);

    let outputs = parse_outputs(&stdout_str(&output));
    assert_eq!(outputs.len(), 3);
    for (i, o) in outputs.iter().enumerate() {
        assert!(o.error.is_none(), "record {} error: {:?}", i, o.error);
    }
    assert_eq!(outputs[0].operation, Operation::Mkdir);
    assert_eq!(outputs[1].operation, Operation::List);
    assert_eq!(outputs[2].operation, Operation::Rmdir);
}

#[test]
fn mixed_success_and_irods_error_in_one_stream() {
    // Three-record stream: valid list (success) → valid envelope
    // for a missing path (in-band iRODS error) → valid list
    // (success). Pins that the dispatcher continues past per-
    // input iRODS errors and that subsequent records are
    // processed normally. Distinct from
    // parse_failure_is_annotated_and_stream_continues (which
    // mixes parse failures with success) and from
    // no_error_flag_suppresses_nonzero_exit_on_per_input_error
    // (which is a single-record stream).
    let local = "/tmp/baton_rs_bin_mixed_src";
    std::fs::write(local, b"binary mixed").expect("write");
    let name = unique_name("baton_rs_bin_mixed");
    let remote = format!("{}/{}", TEST_COLL, name);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote);

    let missing = unique_name("baton_rs_bin_mixed_missing");

    let ok1 = one_envelope_line(BatonDoEnvelope::new_standard(
        Operation::List,
        data_object_target(TEST_COLL, &name),
        Arguments::default(),
    ));
    let bad = one_envelope_line(BatonDoEnvelope::new_standard(
        Operation::List,
        data_object_target(TEST_COLL, &missing),
        Arguments::default(),
    ));
    let ok2 = one_envelope_line(BatonDoEnvelope::new_standard(
        Operation::List,
        data_object_target(TEST_COLL, &name),
        Arguments::default(),
    ));
    let input = format!("{}{}{}", ok1, bad, ok2);

    let output = run_baton_do(&[], &input);
    assert!(
        !output.status.success(),
        "mixed stream with one in-band error should exit non-zero",
    );

    let outputs = parse_outputs(&stdout_str(&output));
    assert_eq!(outputs.len(), 3, "all three records should be emitted");
    assert!(
        outputs[0].error.is_none(),
        "record 0 should succeed: {:?}",
        outputs[0].error
    );
    assert!(
        outputs[1].error.is_some(),
        "record 1 should be annotated with an in-band iRODS error",
    );
    assert!(
        outputs[2].error.is_none(),
        "record 2 should succeed after the prior error: {:?}",
        outputs[2].error
    );
}

#[test]
fn connect_time_recycles_connection_mid_stream() {
    // Set --connect-time to its minimum (10s), feed one record,
    // sleep 11s past the watchdog boundary, then feed a second
    // record. The watchdog should tear down and rebuild the iRODS
    // connection at the record boundary; both records should
    // emit a successful output. End-to-end pin for
    // ReconnectingSession's integration in `baton-do` — the
    // watchdog itself is unit-tested in Session 5c, but no test
    // previously verified the binary-level wiring fires correctly
    // mid-stream.
    //
    // 11-second sleep makes this the slowest test in the suite.
    // Acceptable cost for the only end-to-end coverage of the
    // recycle path.
    let local = "/tmp/baton_rs_bin_recycle_src";
    std::fs::write(local, b"binary recycle").expect("write");
    let name = unique_name("baton_rs_bin_recycle");
    let remote = format!("{}/{}", TEST_COLL, name);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote);

    let line = one_envelope_line(BatonDoEnvelope::new_standard(
        Operation::List,
        data_object_target(TEST_COLL, &name),
        Arguments::default(),
    ));

    let mut child = Command::new(baton_do_path())
        .args(["-c", "10"])
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .expect("spawn baton-do");

    {
        let stdin = child.stdin.as_mut().expect("stdin");
        stdin.write_all(line.as_bytes()).expect("write line 1");
        stdin.flush().expect("flush");
        std::thread::sleep(std::time::Duration::from_secs(11));
        stdin.write_all(line.as_bytes()).expect("write line 2");
        stdin.flush().expect("flush");
    }
    drop(child.stdin.take());

    let output = child.wait_with_output().expect("wait");
    assert!(
        output.status.success(),
        "both records should succeed across the recycle: status={:?} stderr={}",
        output.status,
        String::from_utf8_lossy(&output.stderr),
    );

    let stdout = String::from_utf8(output.stdout).expect("utf8");
    let outputs = parse_outputs(&stdout);
    assert_eq!(outputs.len(), 2, "two records expected: {}", stdout);
    for (i, o) in outputs.iter().enumerate() {
        assert!(
            o.error.is_none(),
            "record {} should succeed across recycle: {:?}",
            i,
            o.error
        );
    }
}

#[test]
fn server_version_flag_prints_xyz_and_exits_zero() {
    // `baton-do --server-version` short-circuits before stdin is
    // consumed: connect, fetch via rcGetMiscSvrInfo, print
    // <X>.<Y>.<Z> on stdout, exit 0. Mirrors upstream baton-do's
    // health-check path used by partisan's
    // `partisan.irods.server_version()` subprocess call
    // (`partisan/src/partisan/irods.py:1603-1610`).
    let mut child = Command::new(baton_do_path())
        .args(["--server-version"])
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .expect("spawn baton-do --server-version");

    // Close stdin without writing — the binary must NOT block
    // waiting for input on the version-probe path.
    drop(child.stdin.take());

    let output = child.wait_with_output().expect("wait_with_output");
    assert!(
        output.status.success(),
        "--server-version should exit 0: status={:?} stderr={:?}",
        output.status,
        String::from_utf8_lossy(&output.stderr)
    );

    let line = String::from_utf8(output.stdout).expect("stdout utf-8");
    let trimmed = line.trim_end();
    let parts: Vec<&str> = trimmed.split('.').collect();
    assert_eq!(
        parts.len(),
        3,
        "--server-version stdout should be 3 dot-separated components, got {:?}",
        trimmed
    );
    for p in &parts {
        assert!(
            !p.is_empty() && p.bytes().all(|b| b.is_ascii_digit()),
            "version component {:?} should be non-empty digits in {:?}",
            p,
            trimmed
        );
    }
    // Final newline matches partisan's `.strip()` expectation: it
    // wouldn't actually fail if missing, but mirroring upstream's
    // `printf("%s\n", ...)` keeps the wire identical.
    assert!(
        line.ends_with('\n'),
        "--server-version output should end with newline, got {:?}",
        line
    );
}

// --- Boundary-input coverage ---------------------------------------------
//
// Pre-Session-7-PR audit flagged that no test covers paths with
// spaces, unicode, or deep nesting on any of the new ops. These
// three tests close that gap with one representative test per
// boundary, each running multi-record streams to exercise the
// full pipeline (clap → NDJSON → deserialiser → dispatcher → FFI
// → iRODS catalog) on non-trivial path shapes.

#[test]
fn boundary_path_with_spaces_through_checksum_and_rm() {
    // Spaces in data-object names round-trip through the JSON
    // envelope, the dispatcher, and the FFI shim's CString
    // construction. Pins coverage for the new ops on a path
    // shape common in real-world iRODS deployments.
    let local = "/tmp/baton_rs_boundary_spaces_src";
    std::fs::write(local, b"boundary spaces").expect("write");
    let name = format!("file with spaces {}", std::process::id());
    let remote = format!("{}/{}", TEST_COLL, name);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote);

    let mut args = Arguments::default();
    args.checksum = true;
    let checksum_env = BatonDoEnvelope::new_standard(
        Operation::Checksum,
        data_object_target(TEST_COLL, &name),
        args,
    );
    let rm_env = BatonDoEnvelope::new_standard(
        Operation::Rm,
        data_object_target(TEST_COLL, &name),
        Arguments::default(),
    );
    let input = format!(
        "{}{}",
        one_envelope_line(checksum_env),
        one_envelope_line(rm_env),
    );
    let output = run_baton_do(&[], &input);
    assert_success_exit(&output);

    let outputs = parse_outputs(&stdout_str(&output));
    assert_eq!(outputs.len(), 2);
    for (i, o) in outputs.iter().enumerate() {
        assert!(o.error.is_none(), "record {} error: {:?}", i, o.error);
    }
}

